vector<int> sequentialDigits(int low, int high) {
    vector<int> result;
    for (int i = low; i <= high; i++) {
        string str = to_string(i);
        int sum = 0;
        for (int j = str.length() - 1; j >= 0; j--) {
            sum += stoi(str.substr(j, 1));
        }
        if (sum == i) {
            result.push_back(i);
        }
    }
    return result;
}

